import React from 'react';
import { ArrowLeft, ArrowRight } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../../context/CartContext';
import api from '../../api/api';
import '../../assets/styles/Featured.css';

const Featured = () => {
  const { addToCart } = useCart();
  const navigate = useNavigate();
  const [featuredProducts, setFeaturedProducts] = React.useState([]);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    const fetchFeatured = async () => {
      try {
        const data = await api.get('/api/products');
        if (data.success) {
          // Identify featured products (those with CURATED or HERITAGE tags in the static seed)
          const featured = data.products.filter(p => 
            p.tag === 'CURATED LUXURY' || p.tag === 'HERITAGE GHEE'
          );
          setFeaturedProducts(featured.map(p => ({
            id: p.id,
            name: p.title,
            price: `₹${p.variants['500g']?.price || p.variants['1kg']?.price}`,
            subtitle: `${p.variants['500g'] ? '500g' : '1kg'} Artisanal Pack`,
            image: p.images[0]
          })));
        }
      } catch (err) {
        console.error('Failed to fetch featured products', err);
      } finally {
        setLoading(false);
      }
    };
    fetchFeatured();
  }, []);

  const parsePrice = (priceStr) => {
    return parseFloat(String(priceStr).replace('₹', '').replace(',', ''));
  };

  const handleQuickAdd = (e, product) => {
    e.preventDefault();
    e.stopPropagation();

    addToCart({
      productId: product.id,
      title: product.name,
      price: parsePrice(product.price),
      image: product.image,
      weight: product.subtitle.split(' ')[0],
      quantity: 1
    });
  };

  const handleBuyNow = async (e, product) => {
    e.preventDefault();
    e.stopPropagation();

    await addToCart({
      productId: product.id,
      title: product.name,
      price: parsePrice(product.price),
      image: product.image,
      weight: product.subtitle.split(' ')[0],
      quantity: 1
    }, false);
    navigate('/checkout');
  };

  if (loading) return null;
  if (featuredProducts.length === 0) return null;

  return (
    <section className="featured-section">
      <div className="featured-header">
        <div className="featured-title-wrapper">
           <span className="featured-tag">CURATION</span>
           <h2 className="featured-title">Featured Essentials</h2>
        </div>
        <div className="featured-arrows">
          <button className="arrow-btn" aria-label="Previous"><ArrowLeft size={20} /></button>
          <button className="arrow-btn" aria-label="Next"><ArrowRight size={20} /></button>
        </div>
      </div>

      <div className="featured-grid">
        {products.map((product) => (
          <Link to={`/product/${product.id}`} key={product.id} className="featured-card" style={{ textDecoration: 'none' }}>
            <div className="card-image-wrapper">
              <img src={product.image} alt={product.name} className="card-image" />
            </div>
            <div className="card-body">
              <div className="card-info">
                 <div className="card-text">
                   <h3 className="card-name">{product.name}</h3>
                   <p className="card-subtitle">{product.subtitle}</p>
                 </div>
                 <span className="card-price">{product.price}</span>
              </div>
              <div className="card-actions">
                <button 
                  className="btn-add-cart"
                  onClick={(e) => handleQuickAdd(e, product)}
                >
                  ADD TO CART
                </button>
                <button 
                  className="btn-buy-now"
                  onClick={(e) => handleBuyNow(e, product)}
                >
                  BUY NOW
                </button>
              </div>
            </div>
          </Link>
        ))}
      </div>
    </section>
  );
};

export default React.memo(Featured);
